export const summarizeArticle = async (articleSummaryInput: ArticleSummaryInput, options?: RequestInit): Promise<ArticleSummary> => {

  return customFetch<ArticleSummary>(getSummarizeArticleUrl(),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(articleSummaryInput)
  }
);}




export const getSummarizeArticleMutationOptions = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof summarizeArticle>>, TError,{data: BodyType<ArticleSummaryInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
): UseMutationOptions<Awaited<ReturnType<typeof summarizeArticle>>, TError,{data: BodyType<ArticleSummaryInput>}, TContext> => {

const mutationKey = ['summarizeArticle'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof summarizeArticle>>, {data: BodyType<ArticleSummaryInput>}> = (props) => {
          const {data} = props ?? {};

          return  summarizeArticle(data,requestOptions)
        }






  return  { mutationFn, ...mutationOptions }}

    export type SummarizeArticleMutationResult = NonNullable<Awaited<ReturnType<typeof summarizeArticle>>>
    export type SummarizeArticleMutationBody = BodyType<ArticleSummaryInput>
    export type SummarizeArticleMutationError = ErrorType<unknown>

